package com.example.crud.data.model

import android.os.Parcel
import android.os.Parcelable

data class Todo(
    var id: String = "",          // Firebase ID
    var title: String = "",
    var description: String = "",
    var status: String = "pending", // pending, completed, hết_hạn
    var deadline: String="",      // ngày + giờ (format: "24/03/2026 14:30")
    var startTime: Long = 0L,
    var endTime: Long = 0L
) : Parcelable {
    constructor(parcel: Parcel) : this(
        parcel.readString() ?: "",
        parcel.readString() ?: "",
        parcel.readString() ?: "",
        parcel.readString() ?: "",
        parcel.readString() ?: "",
        parcel.readLong(),
        parcel.readLong()
    )

    override fun writeToParcel(parcel: Parcel, flags: Int) {
        parcel.writeString(id)
        parcel.writeString(title)
        parcel.writeString(description)
        parcel.writeString(status)
        parcel.writeString(deadline)
        parcel.writeLong(startTime)
        parcel.writeLong(endTime)
    }

    override fun describeContents(): Int {
        return 0
    }

    companion object CREATOR : Parcelable.Creator<Todo> {
        override fun createFromParcel(parcel: Parcel): Todo {
            return Todo(parcel)
        }

        override fun newArray(size: Int): Array<Todo?> {
            return arrayOfNulls(size)
        }
    }
}

package com.example.crud.ui.view.adapter

import android.graphics.Color
import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.example.crud.data.model.StatusUI
import com.example.crud.data.model.Todo
import com.example.crud.databinding.ItemTodoBinding
import com.google.firebase.database.FirebaseDatabase

class TodoAdapter(
    private var todos:List<Todo>,
    private val onDeleteClick: (String) -> Unit,
    private val onUpdateTodoStatus: (String, String)->Unit,
    private val onEditClick: (Todo)->Unit

) : RecyclerView.Adapter<TodoAdapter.TodoViewHolder>() {

    inner class TodoViewHolder(private val binding: ItemTodoBinding) : RecyclerView.ViewHolder(binding.root) {
        fun bind(todo: Todo) {
            // Đặt dữ liệu vào UI
            binding.textViewName.text = todo.title
            binding.textViewDescription.text = todo.description
            binding.textViewDeadline.text = ("Hạn chót: " + todo.deadline)

            // Đặt trạng thái công việc
            val status = todo.status
            val statusUI=convertStatus(status)
            binding.textViewStatus.text = statusUI.text
            binding.textViewStatus.setTextColor(statusUI.color)
            val todoId=todo.id
            // Xử lý nút xóa
            binding.buttonDelete.setOnClickListener {
                onDeleteClick(todoId)
            }

            // Xử lý nút chỉnh sửa (tính năng mở rộng)
            binding.buttonEdit.setOnClickListener {
                onEditClick(todo)
            }
            // Tùy chọn: Ẩn nút hoàn thành nếu đã hoàn thành
            binding.buttonComplete.setOnClickListener {
                val newStatus = if (status == "completed") "pending" else "completed"
                onUpdateTodoStatus(todoId, newStatus)
            }

        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): TodoViewHolder {
        val binding = ItemTodoBinding.inflate(LayoutInflater.from(parent.context), parent, false)
        return TodoViewHolder(binding)
    }

    override fun onBindViewHolder(holder: TodoViewHolder, position: Int) {
        holder.bind(todos[position])
    }

    override fun getItemCount(): Int = todos.size

    fun convertStatus(status: String): StatusUI {
        return when (status) {
            "completed" -> StatusUI("Hoàn thành", Color.GREEN)
            "hết_hạn" -> StatusUI("✗ Hết hạn", Color.RED)
            else -> StatusUI("Chưa hoàn thành", Color.GRAY)
        }
    }
}

package com.example.crud.ui.view.adapter

import android.graphics.Color
import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.example.crud.data.model.StatusUI
import com.example.crud.data.model.Todo
import com.example.crud.databinding.ItemTodoBinding
import com.google.firebase.database.FirebaseDatabase

class TodoAdapter(
    private var todos:List<Todo>,
    private val onDeleteClick: (String) -> Unit,
    private val onUpdateTodoStatus: (String, String)->Unit,
    private val onEditClick: (Todo)->Unit

) : RecyclerView.Adapter<TodoAdapter.TodoViewHolder>() {

    inner class TodoViewHolder(private val binding: ItemTodoBinding) : RecyclerView.ViewHolder(binding.root) {
        fun bind(todo: Todo) {
            // Đặt dữ liệu vào UI
            binding.textViewName.text = todo.title
            binding.textViewDescription.text = todo.description
            binding.textViewDeadline.text = ("Hạn chót: " + todo.deadline)

            // Đặt trạng thái công việc
            val status = todo.status
            val statusUI=convertStatus(status)
            binding.textViewStatus.text = statusUI.text
            binding.textViewStatus.setTextColor(statusUI.color)
            val todoId=todo.id
            // Xử lý nút xóa
            binding.buttonDelete.setOnClickListener {
                onDeleteClick(todoId)
            }

            // Xử lý nút chỉnh sửa (tính năng mở rộng)
            binding.buttonEdit.setOnClickListener {
                onEditClick(todo)
            }
            // Tùy chọn: Ẩn nút hoàn thành nếu đã hoàn thành
            binding.buttonComplete.setOnClickListener {
                val newStatus = if (status == "completed") "pending" else "completed"
                onUpdateTodoStatus(todoId, newStatus)
            }

        }
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): TodoViewHolder {
        val binding = ItemTodoBinding.inflate(LayoutInflater.from(parent.context), parent, false)
        return TodoViewHolder(binding)
    }

    override fun onBindViewHolder(holder: TodoViewHolder, position: Int) {
        holder.bind(todos[position])
    }

    override fun getItemCount(): Int = todos.size

    fun updateTodos(newTodos: List<Todo>) {
        todos = newTodos
        notifyDataSetChanged()
    }

    fun convertStatus(status: String): StatusUI {
        return when (status) {
            "completed" -> StatusUI("Hoàn thành", Color.GREEN)
            "hết_hạn" -> StatusUI("✗ Hết hạn", Color.RED)
            else -> StatusUI("Chưa hoàn thành", Color.GRAY)
        }
    }
}

package com.example.crud

import android.app.DatePickerDialog
import android.app.TimePickerDialog
import android.os.Bundle
import android.util.Log
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import com.example.crud.databinding.ActivityAddTodoBinding
import com.google.firebase.database.FirebaseDatabase
import java.util.Calendar
import java.util.Locale
import java.util.UUID

class addTodo : AppCompatActivity() {
    private lateinit var binding: ActivityAddTodoBinding
    private var selectedDateTime = ""
    private val database = FirebaseDatabase.getInstance()
    override fun onCreate(savedInstanceState: Bundle?)
    {
        super.onCreate(savedInstanceState)
        // Khởi tạo View Binding
        binding = ActivityAddTodoBinding.inflate(layoutInflater)
        setContentView(binding.root)
        setupButtons()
    }

    private fun setupButtons() {
        // Xử lý nút chọn hạn chót
        binding.editTextDeadline.setOnClickListener {
            openDateTimePicker()
        }

        // Xử lý nút quay lại
        binding.buttonCancel.setOnClickListener {
            finish()
        }

        // Xử lý nút lưu
        binding.buttonSave.setOnClickListener {
            handleSave()
        }
    }

    private fun openDateTimePicker() {
        val calendar = Calendar.getInstance()

        // DatePickerDialog
        DatePickerDialog(this, { _, year, month, dayOfMonth ->
            // Sau khi chọn ngày, mở TimePickerDialog
            TimePickerDialog(this, { _, hourOfDay, minute ->
                selectedDateTime = String.format(Locale.getDefault(), "%02d/%02d/%04d %02d:%02d", 
                    dayOfMonth, month + 1, year, hourOfDay, minute)

                binding.editTextDeadline.text = selectedDateTime
            }, calendar.get(Calendar.HOUR_OF_DAY), calendar.get(Calendar.MINUTE), true).show()
        }, calendar.get(Calendar.YEAR), calendar.get(Calendar.MONTH), calendar.get(Calendar.DAY_OF_MONTH)).show()
    }

    private fun handleSave() {
        val taskName = binding.editTextName.text.toString().trim()
        val taskDescription = binding.editTextDescription.text.toString().trim()
        val taskDeadline = selectedDateTime
        // Tạo Todo object
        val todoId = UUID.randomUUID().toString()
        val todoData= Todo(todoId, taskName, taskDescription, "pending",taskDeadline)

        // Lưu lên Firebase
        val todosRef=database.getReference("todos")
        todosRef.child(todoId).setValue(todoData)
            .addOnSuccessListener {
                Toast.makeText(this, "Lưu công việc thành công!", Toast.LENGTH_SHORT).show()
                Log.d("addTodo", "Todo saved: $todoId")
                clearForm()
                finish() // Quay về ListTodo
            }
            .addOnFailureListener { error ->
                Toast.makeText(this, "Lỗi: ${error.message}", Toast.LENGTH_SHORT).show()
                Log.e("addTodo", "Error saving todo", error)
            }
    }

    private fun clearForm() {
        binding.editTextName.text?.clear()
        binding.editTextDescription.text?.clear()
        binding.editTextDeadline.text = getString(R.string.select_deadline)
        selectedDateTime = ""
    }
}

package com.example.crud

import android.app.DatePickerDialog
import android.app.TimePickerDialog
import android.os.Bundle
import android.util.Log
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import com.example.crud.databinding.ActivityAddTodoBinding
import com.google.firebase.database.FirebaseDatabase
import java.util.Calendar
import java.util.Locale
import java.util.UUID

class addTodo : AppCompatActivity() {
    private lateinit var binding: ActivityAddTodoBinding
    private var selectedDateTime = ""
    private val database = FirebaseDatabase.getInstance()
    override fun onCreate(savedInstanceState: Bundle?)
    {
        super.onCreate(savedInstanceState)
        // Khởi tạo View Binding
        binding = ActivityAddTodoBinding.inflate(layoutInflater)
        setContentView(binding.root)
        setupButtons()
    }

    private fun setupButtons() {
        // Xử lý nút chọn hạn chót
        binding.editTextDeadline.setOnClickListener {
            openDateTimePicker()
        }

        // Xử lý nút quay lại
        binding.buttonCancel.setOnClickListener {
            finish()
        }

        // Xử lý nút lưu
        binding.buttonSave.setOnClickListener {
            handleSave()
        }
    }

    private fun openDateTimePicker() {
        val calendar = Calendar.getInstance()

        // DatePickerDialog
        DatePickerDialog(this, { _, year, month, dayOfMonth ->
            // Sau khi chọn ngày, mở TimePickerDialog
            TimePickerDialog(this, { _, hourOfDay, minute ->
                selectedDateTime = String.format(Locale.getDefault(), "%02d/%02d/%04d %02d:%02d", 
                    dayOfMonth, month + 1, year, hourOfDay, minute)

                binding.editTextDeadline.text = selectedDateTime
            }, calendar.get(Calendar.HOUR_OF_DAY), calendar.get(Calendar.MINUTE), true).show()
        }, calendar.get(Calendar.YEAR), calendar.get(Calendar.MONTH), calendar.get(Calendar.DAY_OF_MONTH)).show()
    }

    private fun handleSave() {
        val taskName = binding.editTextName.text.toString().trim()
        val taskDescription = binding.editTextDescription.text.toString().trim()
        val taskDeadline = selectedDateTime

        if (taskName.isEmpty()) {
            Toast.makeText(this, "Vui lòng nhập tên công việc", Toast.LENGTH_SHORT).show()
            return
        }

        // Tạo Todo object
        val todoId = UUID.randomUUID().toString()
        val todoData = Todo(
            id = todoId, 
            title = taskName, 
            description = taskDescription, 
            status = "pending",
            deadline = taskDeadline,
            completed = false
        )

        // Lưu lên Firebase
        val todosRef = database.getReference("todos")
        todosRef.child(todoId).setValue(todoData)
            .addOnSuccessListener {
                Toast.makeText(this, "Lưu công việc thành công!", Toast.LENGTH_SHORT).show()
                Log.d("addTodo", "Todo saved: $todoId")
                clearForm()
                finish() // Quay về ListTodo
            }
            .addOnFailureListener { error ->
                Toast.makeText(this, "Lỗi: ${error.message}", Toast.LENGTH_SHORT).show()
                Log.e("addTodo", "Error saving todo", error)
            }
    }

    private fun clearForm() {
        binding.editTextName.text?.clear()
        binding.editTextDescription.text?.clear()
        binding.editTextDeadline.text = getString(R.string.select_deadline)
        selectedDateTime = ""
    }
}
